import styled from 'styled-components'

export const NavContainer = styled.nav`
  grid-column: 1/3;
  display: flex;
  justify-content: space-between;
  padding: 2em;

  position: sticky;

  & img {
    filter: invert(1);
    width: 2em;
    height: 2em;
  }
`

export const Hamburger = styled.button`
  background: transparent;
  border: 0;
  cursor: pointer;
  width: 3em;
  height: 2em;

  position: relative;

  & > span {
    left: 0;
    display: block;
    width: 100%;
    height: 3px;
    position: absolute;
    
    background: white;
    border-radius: 3px;

    transition: 150ms;
    transition-delay: 150ms;

    &:first-of-type {
      top: 0%;
      /* ${props => props.active && "top: 50%; transition-delay: 0ms"} */
    }

    &:nth-of-type(2) {
      top: 50%;
    }

    &:last-of-type {
      top: 100%;
      /* ${props => props.active && "top: 50%; transition-delay: 0ms"} */
    }
  }
`

export const NavLinks = styled.ul`
  padding: 0;
  margin: 0;
  transition: 150ms ease-out;

  opacity: 0;
  display: flex;
  column-gap: 2em;

  & li a {
    cursor: pointer;
    padding: 1em;
  }

  ${props => props.active && "opacity: 1"}
`
